import React from 'react';

interface ProductCardProps {
  id: string;
  name: string;
  price: number;
  imageUrl: string;
  category: string;
  onEdit: (id: string) => void;
  onDelete: (id: string) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ id, name, price, imageUrl, category, onEdit, onDelete }) => {
  return (
    <div className="bg-gray-800 rounded-2xl shadow-md p-4 hover:shadow-lg transition-shadow">
      <img src={imageUrl} alt={name} className="w-full h-40 object-cover rounded-xl mb-4" />
      <div className="flex justify-between items-center mb-2">
        <h3 className="text-white font-semibold text-lg">{name}</h3>
        <span className="text-indigo-400 font-medium">${price.toFixed(2)}</span>
      </div>
      <p className="text-gray-400 text-sm mb-4">Category: {category}</p>
      <div className="flex justify-between">
        <button
          onClick={() => onEdit(id)}
          className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
        >
          Edit
        </button>
        <button
          onClick={() => onDelete(id)}
          className="px-4 py-2 rounded-lg bg-red-600 text-white hover:bg-red-500 transition"
        >
          Delete
        </button>
      </div>
    </div>
  );
};

export default ProductCard;

