import React from 'react';

interface Order {
  id: string;
  customerName: string;
  totalAmount: number;
  status: string;
  date: string;
}

interface OrderListProps {
  orders: Order[];
  onUpdateStatus: (id: string, status: string) => void;
}

const OrderList: React.FC<OrderListProps> = ({ orders, onUpdateStatus }) => {
  return (
    <div className="bg-gray-900 p-6 rounded-xl shadow-md">
      <h2 className="text-2xl font-semibold text-white mb-4">Order Management</h2>
      <table className="w-full text-left">
        <thead>
          <tr className="text-gray-400">
            <th className="py-2">Order ID</th>
            <th className="py-2">Customer</th>
            <th className="py-2">Total</th>
            <th className="py-2">Status</th>
            <th className="py-2">Date</th>
            <th className="py-2">Actions</th>
          </tr>
        </thead>
        <tbody>
          {orders.map(order => (
            <tr key={order.id} className="text-white hover:bg-gray-800">
              <td className="py-2">{order.id}</td>
              <td className="py-2">{order.customerName}</td>
              <td className="py-2">${order.totalAmount.toFixed(2)}</td>
              <td className="py-2">{order.status}</td>
              <td className="py-2">{order.date}</td>
              <td className="py-2">
                <select
                  value={order.status}
                  onChange={(e) => onUpdateStatus(order.id, e.target.value)}
                  className="bg-gray-700 text-white rounded-lg px-2 py-1"
                >
                  <option value="Pending">Pending</option>
                  <option value="Shipped">Shipped</option>
                  <option value="Completed">Completed</option>
                </select>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default OrderList;
